const UI = `<!doctype html><html lang="ko"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"><title>Agent Company Run</title><style>body{font:14px system-ui;margin:0;background:#111827;color:#e5e7eb}main{max-width:1100px;margin:auto;padding:24px}.card{background:#1f2937;padding:16px;margin:12px 0;border-radius:10px}input,select,button{padding:9px;margin:4px;background:#111827;color:#fff;border:1px solid #4b5563;border-radius:6px}button{cursor:pointer;background:#2563eb}pre{white-space:pre-wrap;overflow:auto;background:#0b1020;padding:12px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}@media(max-width:700px){.grid{grid-template-columns:1fr}}</style></head><body><main><h1>Agent Company 실행 워크스페이스</h1><section class="card"><h2>Project War Room</h2><input id="projectId" placeholder="Project ID"><input id="actorId" value="local-owner" placeholder="Actor ID"><button onclick="loadProject()">프로젝트 조회</button><button onclick="recoverProject()">만료 작업 복구</button><br><input id="boardTaskId" placeholder="Task ID"><input id="principalId" placeholder="담당자 ID"><select id="assigneeKind"><option value="agent">agent</option><option value="human">human</option></select><button onclick="assignTask()">실행 담당 배정</button><select id="boardStatus"><option>in-progress</option><option>review</option><option>blocked</option><option>done</option><option>ready</option></select><button onclick="transitionTask()">상태 변경</button><br><input id="notificationId" placeholder="Notification ID"><button onclick="readNotification()">알림 읽음</button><pre id="warroom">조회 대기</pre></section><section class="card"><h2>실행 요청</h2><input id="runId" placeholder="Run ID"><input id="goal" placeholder="목표"><input id="paths" placeholder="src/file.ts"><select id="risk"><option value="low">low</option><option value="medium">medium</option><option value="high">high</option></select><button onclick="createRun()">생성</button><button onclick="loadRun()">조회</button></section><section class="card"><h2>승인·제어</h2><button onclick="act('approve-plan')">계획 승인</button><button onclick="act('approve-result')">결과 승인</button><button onclick="act('pause')">중지</button><button onclick="act('retry')">재시도</button><button onclick="act('cancel')">취소</button></section><div class="grid"><section class="card"><h2>상태·비용·검증</h2><pre id="summary">조회 대기</pre></section><section class="card"><h2>Diff</h2><pre id="diff">-</pre></section></div><section class="card"><h2>Phase 2 아티팩트·영향·컨텍스트·병합</h2><pre id="phase2">-</pre></section><section class="card"><h2>감사 로그</h2><pre id="audit">-</pre></section></main><script>function uuid(){if(window.crypto&&window.crypto.randomUUID)return window.crypto.randomUUID();var b=new Uint8Array(16);if(window.crypto&&window.crypto.getRandomValues)window.crypto.getRandomValues(b);else for(var i=0;i<16;i++)b[i]=Math.floor(Math.random()*256);b[6]=(b[6]&15)|64;b[8]=(b[8]&63)|128;var h=Array.prototype.map.call(b,function(x){return x.toString(16).padStart(2,'0')}).join('');return h.slice(0,8)+'-'+h.slice(8,12)+'-'+h.slice(12,16)+'-'+h.slice(16,20)+'-'+h.slice(20)}const id=()=>document.querySelector('#runId').value,actor=()=>document.querySelector('#actorId').value,project=()=>document.querySelector('#projectId').value,task=()=>document.querySelector('#boardTaskId').value;async function json(url,opt){const r=await fetch(url,opt);const x=await r.json();if(!r.ok)throw Error(x.error||r.status);return x}const post=(url,body)=>json(url,{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(body)});async function loadProject(){try{warroom.textContent=JSON.stringify(await json('/api/projects/'+encodeURIComponent(project())+'?actor='+encodeURIComponent(actor())),null,2)}catch(e){warroom.textContent=e.message}}async function assignTask(){await post('/api/projects/'+encodeURIComponent(project())+'/tasks/'+encodeURIComponent(task())+'/actions/assign',{actorId:actor(),principalId:principalId.value,kind:assigneeKind.value,responsibility:'executor'});await loadProject()}async function transitionTask(){await post('/api/projects/'+encodeURIComponent(project())+'/tasks/'+encodeURIComponent(task())+'/actions/transition',{actorId:actor(),status:boardStatus.value});await loadProject()}async function recoverProject(){await post('/api/projects/'+encodeURIComponent(project())+'/actions/recover',{actorId:actor()});await loadProject()}async function readNotification(){await post('/api/projects/'+encodeURIComponent(project())+'/notifications/'+encodeURIComponent(notificationId.value)+'/read',{actorId:actor()});await loadProject()}async function createRun(){const body={id:id(),requestId:uuid(),goal:goal.value,requestedPaths:paths.value.split(',').map(x=>x.trim()).filter(Boolean),requestedRisk:risk.value,budgetLimit:10};await post('/api/runs',body);await loadRun()}async function loadRun(){try{const x=await json('/api/runs/'+encodeURIComponent(id()));summary.textContent=JSON.stringify({run:x.run,tasks:x.tasks,approvals:x.approvals,validation:x.result?.validation,cost:x.run?.spent,candidate:x.candidate},null,2);diff.textContent=x.result?.patch||'-';phase2.textContent=JSON.stringify(x.phase2,null,2);audit.textContent=JSON.stringify(x.audit,null,2)}catch(e){summary.textContent=e.message}}async function act(name){await post('/api/runs/'+encodeURIComponent(id())+'/actions/'+name,{userId:actor()});await loadRun()}</script></body></html>`;

