  private async body<T>(request: IncomingMessage): Promise<T> { const chunks: Buffer[] = []; let size = 0; for await (const chunk of request) { const part = Buffer.from(chunk); size += part.length; if (size > 1024 * 1024) throw new Error("Request body too large"); chunks.push(part); } const value=JSON.parse(Buffer.concat(chunks).toString("utf8")) as Record<string,unknown>,principal=this.requestPrincipals.get(request);if(principal){for(const key of ["actorId","userId","ownerId"])if(key in value)value[key]=principal;}return value as T; }
